let mapFileName="",mapRawLines=[],entities=[],wadTextures={},manualTextures={},loadedWADNames=[],activeTab="entities",expandedItems=new Set,editHistory=[],historyPos=-1,dirty=!1,checkedEntities=new Set,editAllGroups=new Set,lastMapFile=null,recentsPanelOpen=!0,currentMapPath=null,tabScrollPositions={},wadBufferCache={};

function getRecents(){try{return JSON.parse(localStorage.getItem("mapmig_recents")||"[]")}catch(e){return[]}}
function addRecent(name,path){if(window.MapMigBridge&&window.MapMigBridge.IS_TAURI){window.MapMigBridge.addRecent(name,path||name).then(()=>renderRecentsFromBridge());return}const recents=getRecents().filter(r=>r.name!==name);recents.unshift({name:name,path:path||name,date:Date.now()});if(recents.length>20)recents.length=20;try{localStorage.setItem("mapmig_recents",JSON.stringify(recents))}catch(e){}renderRecents()}
function renderRecentsFromBridge(){if(!window.MapMigBridge)return;window.MapMigBridge.getRecents().then(recents=>{const list=document.getElementById("recentsList");if(!list)return;if(!recents||recents.length===0){list.innerHTML='<div style="padding:14px;font-size:11px;color:#555;text-align:center">No recent maps</div>';return}let h="";for(const r of recents){const d=new Date(r.date);const ds=d.toLocaleDateString()+" "+d.toLocaleTimeString([],{hour:"2-digit",minute:"2-digit"});h+='<div class="recent-item" data-action="openrecent" data-path="'+esc(r.path)+'" title="'+esc(r.path)+'"><span class="recent-icon">\uD83D\uDDFA</span><span class="recent-name">'+esc(r.name)+'</span><span class="recent-date">'+esc(ds)+"</span></div>"}list.innerHTML=h})}
function clearRecents(){if(window.MapMigBridge&&window.MapMigBridge.IS_TAURI){window.MapMigBridge.clearAllRecents().then(()=>renderRecentsFromBridge());return}try{localStorage.removeItem("mapmig_recents")}catch(e){}renderRecents()}
function renderRecents(){const list=document.getElementById("recentsList");if(!list)return;const recents=getRecents();if(recents.length===0){list.innerHTML='<div style="padding:14px;font-size:11px;color:#555;text-align:center">No recent maps</div>';return}let h="";for(const r of recents){const d=new Date(r.date);const ds=d.toLocaleDateString()+" "+d.toLocaleTimeString([],{hour:"2-digit",minute:"2-digit"});const hasPath=r.path&&window.MapMigBridge&&window.MapMigBridge.IS_TAURI;h+='<div class="recent-item"'+(hasPath?' data-action="openrecent" data-path="'+esc(r.path)+'"':'')+' title="'+(hasPath?esc(r.path):esc(r.name))+'"><span class="recent-icon">\uD83D\uDDFA</span><span class="recent-name">'+esc(r.name)+'</span><span class="recent-date">'+esc(ds)+"</span></div>"}list.innerHTML=h}
function toggleRecentsPanel(){const p=document.getElementById("recentsPanel");const b=document.getElementById("recentsToggleBtn");recentsPanelOpen=!recentsPanelOpen;if(recentsPanelOpen){p.classList.add("open");b.classList.add("active")}else{p.classList.remove("open");b.classList.remove("active")}try{localStorage.setItem("mapmig_recents_open",recentsPanelOpen?"1":"0")}catch(e){}}

function parseMapFile(c){mapRawLines=c.split("\n");entities=[];const L=mapRawLines;let i=0;while(i<L.length){const l=L[i].trim();if(l==="{"){let cm="";for(let j=i-1;j>=0;j--){const p=L[j].trim();if(p.startsWith("//")){cm=p.replace(/^\/\/\s*/,"");break}else if(p===""||p==="}")break;else break}const r=parseEntity(L,i,cm);entities.push(r.entity);i=r.nextIndex}else i++}return entities}

