function parseBrush(L,si,comment){const b={startLine:si,endLine:si,faces:[],faceLines:[],comment:comment||""};let i=si+1;while(i<L.length){const l=L[i].trim();if(l==="}"){b.endLine=i;return{brush:b,nextIndex:i+1}}const m=l.match(/(\(\s*[\d.e+-]+\s+[\d.e+-]+\s+[\d.e+-]+\s*\)\s*\(\s*[\d.e+-]+\s+[\d.e+-]+\s+[\d.e+-]+\s*\)\s*\(\s*[\d.e+-]+\s+[\d.e+-]+\s+[\d.e+-]+\s*\))\s+(\S+)\s+(.*)/);if(m){b.faces.push({planes:m[1],texture:m[2],rest:m[3],lineIndex:i});b.faceLines.push(i)}i++}b.endLine=i;return{brush:b,nextIndex:i}}

function serializeMap(){let o="";for(const e of entities){if(e.comment)o+="// "+e.comment+"\n";o+="{\n";for(const[k,v]of Object.entries(e.properties))o+='"'+k+'" "'+v+'"\n';for(const b of e.brushes){if(b.comment)o+="// "+b.comment+"\n";o+="{\n";for(const f of b.faces)o+=f.planes+" "+f.texture+" "+f.rest+"\n";o+="}\n"}o+="}\n"}return o}

