h+="</div>";
if(!wadDisabled){h+='<div style="margin-top:10px;padding:10px;background:#0d0d1a;border-radius:4px"><div style="font-size:11px;color:#888;margin-bottom:6px">Palette:</div><div style="display:flex;gap:12px;flex-wrap:wrap">';
[["all","All Colors"],["nofb","No Fullbrights"],["fbonly","Fullbrights Only"],["ask","Always Ask"]].forEach(function(o){h+='<label style="font-size:11px;color:#aaa;display:flex;align-items:center;gap:4px;cursor:pointer"><input type="radio" name="palette" value="'+o[0]+'" data-action="setpalette"'+(curPalette===o[0]?" checked":"")+' style="accent-color:#4ec9b0"> '+o[1]+"</label>"});
h+="</div></div>"}
h+="</div></div>";
const showWsBrush=(getSetting("showwsbrush")||"disable")==="enable";
h+='<div class="bulk-section"><div class="bulk-title">\uD83D\uDCCB Display Options</div>';
h+='<div style="margin-top:10px"><label style="font-size:11px;color:#aaa;display:flex;align-items:center;gap:8px;cursor:pointer"><input type="checkbox" data-action="showwsbrush"'+(showWsBrush?" checked":"")+' style="accent-color:#4ec9b0"> Show Brush Textures for worldspawn entities</label></div>';
h+="</div>";
const pWads=getPersistentWADNames();const singleUseWads=loadedWADNames.filter(n=>!pWads.includes(n));const disabledTip=wadDisabled?"WAD exporting is disabled":"";
