// Persistent WAD storage via IndexedDB
function openWADDB(){return new Promise((res,rej)=>{const rq=indexedDB.open("MapMigWADs",1);rq.onupgradeneeded=e=>{e.target.result.createObjectStore("wads",{keyPath:"name"})};rq.onsuccess=e=>res(e.target.result);rq.onerror=e=>rej(e.target.error)})}
async function savePersistentWAD(name,arrayBuffer){const db=await openWADDB();return new Promise((res,rej)=>{const tx=db.transaction("wads","readwrite");tx.objectStore("wads").put({name:name,data:arrayBuffer});tx.oncomplete=()=>res();tx.onerror=e=>rej(e.target.error)})}
async function removePersistentWAD(name){const db=await openWADDB();return new Promise((res,rej)=>{const tx=db.transaction("wads","readwrite");tx.objectStore("wads").delete(name);tx.oncomplete=()=>res();tx.onerror=e=>rej(e.target.error)})}
async function loadAllPersistentWADs(){try{const db=await openWADDB();return new Promise((res,rej)=>{const tx=db.transaction("wads","readonly");const rq=tx.objectStore("wads").getAll();rq.onsuccess=()=>res(rq.result||[]);rq.onerror=e=>rej(e.target.error)})}catch(e){return[]}}
function getPersistentWADNames(){return persistentWADNames||[]}
let persistentWADNames=[];
async function initPersistentWADs(){try{const all=await loadAllPersistentWADs();persistentWADNames=[];for(const w of all){try{const texs=await parseWAD(w.data);Object.assign(wadTextures,texs);if(!loadedWADNames.includes(w.name))loadedWADNames.push(w.name);persistentWADNames.push(w.name)}catch(e){console.warn("Failed to load persistent WAD:",w.name,e)}}}catch(e){console.warn("IndexedDB not available:",e)}}
async function refreshWADs(){showToast("Reloading WAD files...");let count=0;// Reload persistent WADs
try{const all=await loadAllPersistentWADs();for(const w of all){try{const texs=await parseWAD(w.data);Object.assign(wadTextures,texs);count+=Object.keys(texs).length}catch(e){console.warn("Failed to reload WAD:",w.name,e)}}}catch(e){}
// Reload single-use WADs from cache
for(const[name,buf] of Object.entries(wadBufferCache)){if(!persistentWADNames.includes(name)){try{const texs=await parseWAD(buf);Object.assign(wadTextures,texs);count+=Object.keys(texs).length}catch(e){console.warn("Failed to reload cached WAD:",name,e)}}}
showToast("Reloaded "+count+" textures from "+loadedWADNames.length+" WAD"+(loadedWADNames.length!==1?"s":""));renderSidebar();renderResults()}
function getSetting(k){try{return localStorage.getItem("mapmig_"+k)}catch(e){return null}}
function setSetting(k,v){try{localStorage.setItem("mapmig_"+k,v)}catch(e){}}

function mmConfirm(msg,onYes){const dlg=document.createElement("div");dlg.style.cssText="position:fixed;inset:0;background:rgba(0,0,0,0.7);z-index:2000;display:flex;align-items:center;justify-content:center";dlg.innerHTML='<div style="background:#111128;border:1px solid #2a2a4a;border-radius:8px;padding:24px;max-width:400px;width:90%;text-align:center"><div style="font-size:13px;color:#d0d0d0;margin-bottom:20px;white-space:pre-line">'+esc(msg)+'</div><div style="display:flex;gap:8px;justify-content:center"><button id="mmcYes" style="background:#4ec9b0;color:#0d0d1a;border:none;padding:8px 20px;border-radius:4px;cursor:pointer;font-weight:600;font-size:12px">Yes</button><button id="mmcNo" style="background:transparent;color:#888;border:1px solid #2a2a4a;padding:8px 20px;border-radius:4px;cursor:pointer;font-size:12px">Cancel</button></div></div>';document.body.appendChild(dlg);dlg.querySelector("#mmcYes").onclick=()=>{dlg.remove();onYes()};dlg.querySelector("#mmcNo").onclick=()=>{dlg.remove()}}
function handleClick(e){const tgt=e.target.closest("[data-action]");if(!tgt){const row=e.target.closest(".result-row[data-key]");if(row){toggle(row.dataset.key);renderResults();return}const ih=e.target.closest(".ent-instance-header[data-key]");if(ih){toggle(ih.dataset.key);renderResults();return}const sp=e.target.closest("[data-key]");if(sp&&!sp.classList.contains("result-item")){toggle(sp.dataset.key);renderResults();return}return}const a=tgt.dataset.action;if(a==="set"){setEP(+tgt.dataset.ei,tgt.dataset.key.replace(/&quot;/g,'"'),tgt.value);renderSidebar()}else if(a==="del"){delEP(+tgt.dataset.ei,tgt.dataset.key.replace(/&quot;/g,'"'));renderResults();renderSidebar()}else if(a==="add"){const ei=+tgt.dataset.ei,kE=document.getElementById("newkey_"+ei),vE=document.getElementById("newval_"+ei);if(kE&&kE.value.trim()){addEP(ei,kE.value.trim(),vE?vE.value:"");renderResults();renderSidebar()}}else if(a==="facetex"){repFT(+tgt.dataset.ei,+tgt.dataset.bi,+tgt.dataset.fi,tgt.value);renderSidebar()}else if(a==="loadtex"&&tgt.dataset.texname){trigManTex(tgt.dataset.texname)}else if(a==="bulktexrepl"){const ot=tgt.dataset.oldtex,inp=document.getElementById(tgt.dataset.inputid);if(ot&&inp&&inp.value.trim()){const c=bulkRTWithPrompt(ot,inp.value.trim());showToast(c+" faces updated");renderResults();renderSidebar()}}else if(a==="renametex"){const oldName=tgt.dataset.oldtex,inp=document.getElementById(tgt.dataset.inputid);if(!oldName||!inp||!inp.value.trim())return;const newName=inp.value.trim();if(newName===oldName)return;const oldKey=oldName.toLowerCase(),newKey=newName.toLowerCase();const existingNew=getTex(newName);const existingOld=getTex(oldName);if(existingNew&&existingOld){const oldIsManual=!!manualTextures[oldKey];const newIsManual=!!manualTextures[newKey];const oldURL=existingOld.dataURL||"";const newURL=existingNew.dataURL||"";const dlg=document.createElement("div");dlg.style.cssText="position:fixed;inset:0;background:rgba(0,0,0,0.7);z-index:2000;display:flex;align-items:center;justify-content:center";dlg.innerHTML='<div style="background:#111128;border:1px solid #2a2a4a;border-radius:8px;padding:24px;max-width:520px;width:90%"><div style="font-size:14px;font-weight:600;margin-bottom:12px;color:#e8b931">\u26A0 Texture Conflict</div><div style="font-size:12px;color:#888;margin-bottom:16px">Both "'+esc(oldName)+'" and "'+esc(newName)+'" have loaded textures. Which do you want to keep?</div><div style="display:flex;gap:16px;justify-content:center;margin-bottom:16px"><div style="text-align:center"><label style="cursor:pointer;display:block"><input type="radio" name="texconflict" value="old" checked style="accent-color:#4ec9b0">'+(oldURL?'<img src="'+oldURL+'" style="display:block;width:96px;height:96px;image-rendering:pixelated;border:1px solid #2a2a4a;border-radius:4px;margin:8px auto">':'<div style="width:96px;height:96px;background:#1a1a2e;display:flex;align-items:center;justify-content:center;border:1px solid #2a2a4a;border-radius:4px;margin:8px auto;font-size:10px;color:#555">\u26A0</div>')+'<div style="font-size:10px;color:#aaa;font-family:Consolas,monospace">'+esc(oldName)+'</div>'+(oldIsManual?'<div style="font-size:9px;color:#e8b931">manual</div>':'<div style="font-size:9px;color:#6a9955">from WAD</div>')+'</label></div><div style="text-align:center"><label style="cursor:pointer;display:block"><input type="radio" name="texconflict" value="new" style="accent-color:#4ec9b0">'+(newURL?'<img src="'+newURL+'" style="display:block;width:96px;height:96px;image-rendering:pixelated;border:1px solid #2a2a4a;border-radius:4px;margin:8px auto">':'<div style="width:96px;height:96px;background:#1a1a2e;display:flex;align-items:center;justify-content:center;border:1px solid #2a2a4a;border-radius:4px;margin:8px auto;font-size:10px;color:#555">\u26A0</div>')+'<div style="font-size:10px;color:#aaa;font-family:Consolas,monospace">'+esc(newName)+'</div>'+(newIsManual?'<div style="font-size:9px;color:#e8b931">manual</div>':'<div style="font-size:9px;color:#6a9955">from WAD</div>')+'</label></div></div><div style="display:flex;gap:8px;justify-content:center"><button id="texConflictOk" style="background:#4ec9b0;color:#0d0d1a;border:none;padding:8px 20px;border-radius:4px;cursor:pointer;font-weight:600;font-size:12px">Confirm</button><button id="texConflictCancel" style="background:transparent;color:#888;border:1px solid #2a2a4a;padding:8px 20px;border-radius:4px;cursor:pointer;font-size:12px">Cancel</button></div></div>';document.body.appendChild(dlg);dlg.querySelector("#texConflictCancel").onclick=()=>dlg.remove();dlg.querySelector("#texConflictOk").onclick=()=>{const choice=dlg.querySelector('input[name="texconflict"]:checked').value;dlg.remove();if(choice==="old"){const oldTex=manualTextures[oldKey];if(oldTex){delete manualTextures[oldKey];oldTex.name=newName;manualTextures[newKey]=oldTex}else if(wadTextures[oldKey]){delete wadTextures[newKey];delete manualTextures[newKey]}}else{if(manualTextures[oldKey])delete manualTextures[oldKey]}bulkRT(oldName,newName);dirty=true;updateSave();showToast("Renamed: "+oldName+" \u2192 "+newName);renderResults();renderSidebar();renderEditHistory()}}else{const oldTex=manualTextures[oldKey];if(oldTex){delete manualTextures[oldKey];oldTex.name=newName;manualTextures[newKey]=oldTex}else{const wadTex=wadTextures[oldKey];if(wadTex){manualTextures[newKey]={...wadTex,name:newName,fromWAD:false}}}bulkRT(oldName,newName);dirty=true;updateSave();showToast("Renamed: "+oldName+" \u2192 "+newName);renderResults();renderSidebar();renderEditHistory()}}else if(a==="bulktex"){const f=document.getElementById("bulkTexFrom").value,t=document.getElementById("bulkTexTo").value.trim();if(f&&t){showToast(bulkRTWithPrompt(f,t)+" faces updated");renderResults();renderSidebar()}}else if(a==="bulkset"){const cn=document.getElementById("bulkEntClass").value,k=document.getElementById("bulkEntKey").value.trim(),v=document.getElementById("bulkEntVal").value;if(cn&&k){const g=getEntityGroups().find(x=>x.name===cn);if(g){showToast(bulkSP(g.indices,k,v)+" entities updated");renderResults();renderSidebar()}}}else if(a==="bulkdel"){const cn=document.getElementById("bulkEntClass").value,k=document.getElementById("bulkEntKey").value.trim();if(cn&&k){mmConfirm('Delete key "'+k+'" from all '+cn+" entities?",()=>{const g=getEntityGroups().find(x=>x.name===cn);if(g){showToast(bulkDP(g.indices,k)+" entities updated");renderResults();renderSidebar()}})}}else if(a==="delallents"){const cn=tgt.dataset.cn;mmConfirm("Delete ALL "+cn+" entities from the map?\nThis cannot be undone.",()=>{const g=getEntityGroups().find(x=>x.name===cn);if(g){const c=deleteEntities(g.indices);showToast(c+" entities deleted");editAllGroups.delete(cn);renderResults();renderSidebar()}})}else if(a==="delselents"){const idx=tgt.dataset.indices.split(",").map(Number);const label=idx.length===1?"this entity":idx.length+" entities";mmConfirm("Delete "+label+" from the map?\nThis cannot be undone.",()=>{const c=deleteEntities(idx);showToast(c+" entit"+(c!==1?"ies":"y")+" deleted");renderResults();renderSidebar()})}else if(a==="wadexp-keep"){doWADExp(!0)}else if(a==="wadexp-strip"){doWADExp(!1)}else if(a==="wadexp-skip"){skipWADExp()}else if(a==="openrecent"){const el=tgt.closest("[data-path]");if(el&&el.dataset.path){console.log("[MapMig] Opening recent, path:",el.dataset.path);loadMap(el.dataset.path).catch(err=>{showToast("Failed to open: "+err);console.error("[MapMig] openrecent error:",err)})}}else if(a==="addpersistwad"){const inp=document.createElement("input");inp.type="file";inp.accept=".wad";inp.multiple=!0;inp.onchange=async()=>{for(const f of inp.files){try{const buf=await f.arrayBuffer();const texs=await parseWAD(buf);Object.assign(wadTextures,texs);if(!loadedWADNames.includes(f.name))loadedWADNames.push(f.name);await savePersistentWAD(f.name,buf);if(!persistentWADNames.includes(f.name))persistentWADNames.push(f.name);showToast("Persistent WAD added: "+f.name)}catch(err){showToast("WAD error: "+err.message)}}renderSidebar();renderResults()};inp.click()}else if(a==="rmpersistwad"){const wn=tgt.dataset.wn;mmConfirm('Remove WAD "'+wn+'" from auto-load list?\nIt will no longer auto-load with new maps.',()=>{removePersistentWAD(wn);persistentWADNames=persistentWADNames.filter(n=>n!==wn);loadedWADNames=loadedWADNames.filter(n=>n!==wn);showToast("Removed: "+wn);renderSidebar();renderResults()})}else if(a==="promotewad"){const wn=tgt.dataset.wn;if(!persistentWADNames.includes(wn)){const buf=wadBufferCache[wn];if(buf){savePersistentWAD(wn,buf).then(()=>{persistentWADNames.push(wn);showToast("Added to auto-load: "+wn);renderResults()}).catch(err=>showToast("Error: "+err))}else{showToast("WAD buffer not available \u2014 reload and try again")}}}else if(a==="rmsingleusewad"){const wn=tgt.dataset.wn;loadedWADNames=loadedWADNames.filter(n=>n!==wn);showToast("Removed: "+wn);renderSidebar();renderResults()}else if(a==="setgame"){setSetting("game",tgt.value);showToast("Game set to: "+tgt.value)}else if(a==="setbackup"){setSetting("backup",tgt.checked?"enable":"disable")}else if(a==="setwadmode"){setSetting("wadmode",tgt.value);renderResults()}else if(a==="setpalette"){setSetting("palette",tgt.value)}else if(a==="setautopersistwad"){setSetting("autopersistwad",tgt.checked?"enable":"disable")}else if(a==="showwsbrush"){setSetting("showwsbrush",tgt.checked?"enable":"disable");if(entities.length)renderResults()}else if(a==="openwadpicker"){const tid=tgt.dataset.targetid;showWADTexturePicker(tid)}else if(a==="pickwadtex"){const tid=tgt.dataset.targetid,tn=tgt.dataset.texname;const inp=document.getElementById(tid);if(inp){inp.value=tn;const btnId=tid.replace("texrepl_","texreplbtn_");const btn=document.getElementById(btnId);if(btn&&tn){btn.classList.add("btn-glow")}else if(btn){btn.classList.remove("btn-glow")}}const dlg=document.getElementById("wadPickerDlg");if(dlg)dlg.remove()}else if(a==="histjump"){const idx=+tgt.dataset.histidx;undoRedoToIndex(idx)}else if(a==="checkent"){const ei=+tgt.dataset.ei;if(tgt.checked)checkedEntities.add(ei);else checkedEntities.delete(ei);renderResults()}else if(a==="editall"){const cn=tgt.dataset.cn;if(tgt.checked)editAllGroups.add(cn);else editAllGroups.delete(cn);renderResults()}else if(a==="multiset"){const idx=tgt.dataset.indices.split(",").map(Number),k=tgt.dataset.key.replace(/&quot;/g,'"'),v=tgt.value;if(v!==""){let changed=0;const olds={};for(const i of idx){if(entities[i].properties[k]!==v){olds[i]=entities[i].properties[k];entities[i].properties[k]=v;changed++}}if(changed){pushEdit({type:"bulk_prop",key:k,value:v,count:changed,indices:Object.keys(olds).map(Number),oldValues:olds})}renderSidebar()}}else if(a==="multidel"){const idx=tgt.dataset.indices.split(",").map(Number),k=tgt.dataset.key.replace(/&quot;/g,'"');let c=0;const olds={};for(const i of idx)if(entities[i].properties[k]!==undefined){olds[i]=entities[i].properties[k];delete entities[i].properties[k];c++}if(c){pushEdit({type:"bulk_del_prop",key:k,count:c,indices:Object.keys(olds).map(Number),oldValues:olds})}renderResults();renderSidebar()}else if(a==="multiadd"){const idx=tgt.dataset.indices.split(",").map(Number),grp=tgt.dataset.group,kE=document.getElementById("multinewkey_"+grp),vE=document.getElementById("multinewval_"+grp);if(kE&&kE.value.trim()){const k=kE.value.trim(),v=vE?vE.value:"";const olds={};for(const i of idx){olds[i]=entities[i].properties[k];entities[i].properties[k]=v}pushEdit({type:"bulk_prop",key:k,value:v,count:idx.length,indices:idx.slice(),oldValues:olds});renderResults();renderSidebar()}}}

function handleChange(e){const t=e.target.closest("[data-action]");if(!t)return;if(t.dataset.action==="set"){setEP(+t.dataset.ei,t.dataset.key.replace(/&quot;/g,'"'),t.value);renderSidebar()}else if(t.dataset.action==="facetex"){repFT(+t.dataset.ei,+t.dataset.bi,+t.dataset.fi,t.value);renderSidebar()}else if(t.dataset.action==="multiset"){const idx=t.dataset.indices.split(",").map(Number),k=t.dataset.key.replace(/&quot;/g,'"'),v=t.value;if(v!==""){let changed=0;const olds={};for(const i of idx){if(entities[i].properties[k]!==v){olds[i]=entities[i].properties[k];entities[i].properties[k]=v;changed++}}if(changed){pushEdit({type:"bulk_prop",key:k,value:v,count:changed,indices:Object.keys(olds).map(Number),oldValues:olds})}renderSidebar()}}else if(t.dataset.action==="setgame"){setSetting("game",t.value);showToast("Game set to: "+t.value)}else if(t.dataset.action==="setbackup"){setSetting("backup",t.checked?"enable":"disable")}else if(t.dataset.action==="setwadmode"){setSetting("wadmode",t.value);renderResults()}else if(t.dataset.action==="setautopersistwad"){setSetting("autopersistwad",t.checked?"enable":"disable")}}

function toggle(k){expandedItems.has(k)?expandedItems.delete(k):expandedItems.add(k)}
function esc(s){return s?String(s).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;"):""}
function css(s){return String(s).replace(/[^a-zA-Z0-9_-]/g,"_")}
function showToast(m){const t=document.getElementById("toast");t.textContent=m;t.style.display="block";t.style.opacity="1";setTimeout(()=>{t.style.opacity="0";setTimeout(()=>{t.style.display="none"},300)},2000)}
function trigManTex(n){const inp=document.createElement("input");inp.type="file";inp.accept=".tga,.png,.bmp,.jpg,.jpeg,.vtf,.pcx";inp.onchange=async()=>{if(!inp.files.length)return;try{let t=await loadExternalImage(inp.files[0]);t.name=n;
// Resize if larger than 512px on either side
const maxDim=512;if(t.width>maxDim||t.height>maxDim){const scale=Math.min(maxDim/t.width,maxDim/t.height);const nw=Math.round(t.width*scale),nh=Math.round(t.height*scale);const cv=document.createElement("canvas");cv.width=nw;cv.height=nh;const cx=cv.getContext("2d");
// Need to draw from the original image data
const srcCv=document.createElement("canvas");srcCv.width=t.width;srcCv.height=t.height;const srcCx=srcCv.getContext("2d");if(t.imageData){srcCx.putImageData(t.imageData,0,0)}else{const img=new Image;await new Promise((res,rej)=>{img.onload=res;img.onerror=rej;img.src=t.dataURL});srcCx.drawImage(img,0,0)}
cx.drawImage(srcCv,0,0,nw,nh);t.imageData=cx.getImageData(0,0,nw,nh);t.dataURL=cv.toDataURL("image/png");t.width=nw;t.height=nh;showToast("Resized to "+nw+"\u00D7"+nh)}
manualTextures[n.toLowerCase()]=t;showToast("Texture loaded: "+n);renderSidebar();renderResults()}catch(e){showToast("Error: "+e.message)}};inp.click()}

// --- Texture Import System ---
function getMapTexNames(){return getAllTextures().map(t=>t.name)}
function texBaseName(n){const i=n.lastIndexOf("/");return i>=0?n.substring(i+1):n}
function shortenName(fullPath,maxLen){maxLen=maxLen||15;const base=texBaseName(fullPath);if(base.length<=maxLen)return base;const parts=fullPath.split("/");if(parts.length>=2){const dir=parts[parts.length-2].substring(0,Math.min(5,parts.length>=2?parts[parts.length-2].length:0));const file=base.substring(0,maxLen-dir.length-1);const candidate=dir+"_"+file;if(candidate.length<=maxLen)return candidate}const noVowels=base.replace(/[aeiouAEIOU]/g,"");if(noVowels.length<=maxLen)return noVowels.substring(0,maxLen);return noVowels.substring(0,maxLen-3)+"001"}
function findUniqueShort(fullPath,existing,maxLen){maxLen=maxLen||15;let candidate=shortenName(fullPath,maxLen);let attempt=1;while(existing.has(candidate.toLowerCase())){const numStr=String(attempt).padStart(3,"0");candidate=candidate.substring(0,maxLen-3)+numStr;attempt++}return candidate}
function showRenameModal(texName,thumbDataURL,suggestedName){return new Promise((resolve)=>{const dlg=document.createElement("div");dlg.style.cssText="position:fixed;inset:0;background:rgba(0,0,0,0.7);z-index:2000;display:flex;align-items:center;justify-content:center";let sug=suggestedName||shortenName(texName);dlg.innerHTML='<div style="background:#111128;border:1px solid #2a2a4a;border-radius:8px;padding:24px;max-width:420px;width:90%;text-align:center"><div style="font-size:14px;font-weight:600;margin-bottom:12px;color:#e8b931">\u26A0 Texture Name Too Long</div>'+(thumbDataURL?'<div style="margin-bottom:12px"><img src="'+thumbDataURL+'" style="max-width:96px;max-height:96px;image-rendering:pixelated;border:1px solid #2a2a4a;border-radius:4px"></div>':'')+'<div style="font-size:12px;color:#888;margin-bottom:4px">Original name:</div><div style="font-size:11px;color:#d16969;font-family:Consolas,monospace;margin-bottom:12px;word-break:break-all">'+esc(texName)+' ('+texName.length+' chars)</div><div style="font-size:12px;color:#888;margin-bottom:8px">Enter a compatible name (max 15 chars):</div><div style="display:flex;gap:8px;margin-bottom:16px"><input type="text" id="renameInput" class="kv-input" value="'+esc(sug)+'" maxlength="15" style="flex:1;text-align:center;font-family:Consolas,monospace"></div><div style="display:flex;gap:8px;justify-content:center"><button id="renameConfirm" style="background:#4ec9b0;color:#0d0d1a;border:none;padding:8px 20px;border-radius:4px;cursor:pointer;font-weight:600;font-size:12px">Confirm</button><button id="renameSkip" style="background:transparent;color:#888;border:1px solid #2a2a4a;padding:8px 20px;border-radius:4px;cursor:pointer;font-size:12px">Skip</button></div></div>';document.body.appendChild(dlg);const inp=dlg.querySelector("#renameInput");const btn=dlg.querySelector("#renameConfirm");inp.focus();inp.select();const updateBtn=()=>{const v=inp.value.trim();btn.disabled=!v||v.length>15||v.includes("/");btn.style.opacity=btn.disabled?"0.4":"1"};inp.addEventListener("input",updateBtn);updateBtn();btn.addEventListener("click",()=>{dlg.remove();resolve(inp.value.trim())});dlg.querySelector("#renameSkip").addEventListener("click",()=>{dlg.remove();resolve(null)})})}
async function importImageFile(){if(!entities.length){showToast("Load a map first");return}const inp=document.getElementById("imgFileInput");inp.value="";inp.onchange=async()=>{if(!inp.files.length)return;const file=inp.files[0];try{const tex=await loadExternalImage(file);const mapTexNames=getMapTexNames();const baseList={};for(const n of mapTexNames){const bn=texBaseName(n);if(!baseList[bn.toLowerCase()])baseList[bn.toLowerCase()]={base:bn,originals:[]};baseList[bn.toLowerCase()].originals.push(n)}const fileBase=tex.name;let matchName=null;const entry=baseList[fileBase.toLowerCase()];if(entry){matchName=fileBase}if(!matchName){showToast("No matching texture found for: "+fileBase);return}if(fileBase.length>15||fileBase.includes("/")){const newName=await showRenameModal(fileBase,tex.dataURL,shortenName(fileBase));if(!newName){showToast("Skipped: "+fileBase);return}tex.name=newName;for(const orig of entry.originals){bulkRT(orig,newName)}manualTextures[newName.toLowerCase()]=tex;dirty=true;updateSave();showToast("Imported & renamed: "+newName)}else{tex.name=fileBase;for(const orig of entry.originals){if(orig!==fileBase)bulkRT(orig,fileBase)}manualTextures[fileBase.toLowerCase()]=tex;dirty=true;updateSave();showToast("Imported: "+fileBase)}renderSidebar();renderResults();renderEditHistory()}catch(e){showToast("Import error: "+e.message)}};inp.click()}
async function importImagesFolder(){if(!entities.length){showToast("Load a map first");return}if(window.MapMigBridge&&window.MapMigBridge.IS_TAURI){try{const folderPath=await window.__TAURI_INTERNALS__.invoke("plugin:dialog|open",{options:{directory:true,multiple:false}});if(!folderPath)return;const allFiles=await window.__TAURI_INTERNALS__.invoke("list_directory_recursive",{path:folderPath});const imgExts=new Set(["tga","png","bmp","jpg","jpeg","vtf","pcx"]);const imageFiles=allFiles.filter(f=>{const ext=f.split(".").pop().toLowerCase();return imgExts.has(ext)});if(!imageFiles.length){showToast("No image files found in folder");return}const folderName=folderPath.replace(/\\/g,"/").split("/").pop();const mapTexNames=getMapTexNames();const baseList={};const pathList={};for(const n of mapTexNames){const bn=texBaseName(n).toLowerCase();if(!baseList[bn])baseList[bn]={originals:[]};baseList[bn].originals.push(n);pathList[n.toLowerCase()]=n}showToast("Processing "+imageFiles.length+" images...");const matched=[];const conflicts=new Map;const usedNames=new Set(Object.keys(manualTextures));for(const filePath of imageFiles){const normPath=filePath.replace(/\\/g,"/");const folderIdx=normPath.toLowerCase().indexOf(folderName.toLowerCase()+"/");const relPath=folderIdx>=0?normPath.substring(folderIdx+folderName.length+1):normPath.split("/").pop();const innerNoExt=relPath.replace(/\.[^.]+$/,"");const fileBase=normPath.split("/").pop().replace(/\.[^.]+$/,"");const baseKey=fileBase.toLowerCase();const pathKey=innerNoExt.toLowerCase();let matchedOriginals=null;if(pathList[pathKey]){matchedOriginals=[pathList[pathKey]]}else if(baseList[baseKey]){if(baseList[baseKey].originals.length===1){matchedOriginals=baseList[baseKey].originals}else{const existing=conflicts.get(baseKey)||[];existing.push({filePath:filePath,innerPath:innerNoExt,originals:baseList[baseKey].originals});conflicts.set(baseKey,existing);continue}}if(matchedOriginals){matched.push({filePath:filePath,fileBase:fileBase,innerPath:innerNoExt,originals:matchedOriginals})}}for(const item of matched){try{const buf=await window.MapMigBridge.readBinaryFile(item.filePath);const blob=new Blob([buf]);const file=new File([blob],item.filePath.split(/[\\/]/).pop());const tex=await loadExternalImage(file);let finalName=item.fileBase;if(finalName.length>15||finalName.includes("/")){const newName=await showRenameModal(item.innerPath,tex.dataURL,findUniqueShort(item.innerPath,usedNames));if(!newName)continue;finalName=newName}tex.name=finalName;for(const orig of item.originals){if(orig!==finalName)bulkRT(orig,finalName)}manualTextures[finalName.toLowerCase()]=tex;usedNames.add(finalName.toLowerCase())}catch(e){console.warn("Failed to import:",item.filePath,e)}}if(conflicts.size>0){for(const[baseKey,entries] of conflicts){for(const entry of entries){try{const buf=await window.MapMigBridge.readBinaryFile(entry.filePath);const blob=new Blob([buf]);const file=new File([blob],entry.filePath.split(/[\\/]/).pop());const tex=await loadExternalImage(file);const suggested=findUniqueShort(entry.innerPath,usedNames);let finalName=entry.filePath.split(/[\\/]/).pop().replace(/\.[^.]+$/,"");if(finalName.length>15||finalName.includes("/")||usedNames.has(finalName.toLowerCase())){const newName=await showRenameModal(entry.innerPath,tex.dataURL,suggested);if(!newName)continue;finalName=newName}tex.name=finalName;for(const orig of entry.originals){const pathMatch=orig.toLowerCase()===entry.innerPath.toLowerCase();if(pathMatch||entry.originals.length===1){bulkRT(orig,finalName)}}manualTextures[finalName.toLowerCase()]=tex;usedNames.add(finalName.toLowerCase())}catch(e){console.warn("Failed to import:",entry.filePath,e)}}}}dirty=true;updateSave();renderSidebar();renderResults();renderEditHistory();showToast("Folder import complete")}catch(err){showToast("Folder import error: "+err)}}else{const inp=document.getElementById("imgFolderInput");inp.value="";inp.onchange=async()=>{if(!inp.files.length)return;const imgExts=new Set(["tga","png","bmp","jpg","jpeg","vtf","pcx"]);const files=Array.from(inp.files).filter(f=>{const ext=f.name.split(".").pop().toLowerCase();return imgExts.has(ext)});if(!files.length){showToast("No image files found in folder");return}const mapTexNames=getMapTexNames();const baseList={};const pathList={};for(const n of mapTexNames){const bn=texBaseName(n).toLowerCase();if(!baseList[bn])baseList[bn]={originals:[]};baseList[bn].originals.push(n);pathList[n.toLowerCase()]=n}showToast("Processing "+files.length+" images...");const matched=[];const conflicts=new Map;const usedNames=new Set(Object.keys(manualTextures));for(const file of files){const relPath=file.webkitRelativePath||file.name;const parts=relPath.split("/");parts.shift();const innerPath=parts.join("/");const innerNoExt=innerPath.replace(/\.[^.]+$/,"");const fileBase=file.name.replace(/\.[^.]+$/,"");const baseKey=fileBase.toLowerCase();const pathKey=innerNoExt.toLowerCase();let matchedOriginals=null;if(pathList[pathKey]){matchedOriginals=[pathList[pathKey]]}else if(baseList[baseKey]){if(baseList[baseKey].originals.length===1){matchedOriginals=baseList[baseKey].originals}else{const existing=conflicts.get(baseKey)||[];existing.push({file:file,innerPath:innerNoExt,originals:baseList[baseKey].originals});conflicts.set(baseKey,existing);continue}}if(matchedOriginals){matched.push({file:file,fileBase:fileBase,innerPath:innerNoExt,originals:matchedOriginals})}}for(const item of matched){try{const tex=await loadExternalImage(item.file);let finalName=item.fileBase;if(finalName.length>15||finalName.includes("/")){const newName=await showRenameModal(item.innerPath,tex.dataURL,findUniqueShort(item.innerPath,usedNames));if(!newName)continue;finalName=newName}tex.name=finalName;for(const orig of item.originals){if(orig!==finalName)bulkRT(orig,finalName)}manualTextures[finalName.toLowerCase()]=tex;usedNames.add(finalName.toLowerCase())}catch(e){console.warn("Failed to import:",item.file.name,e)}}if(conflicts.size>0){for(const[baseKey,entries] of conflicts){for(const entry of entries){try{const tex=await loadExternalImage(entry.file);const suggested=findUniqueShort(entry.innerPath,usedNames);let finalName=entry.fileBase;if(finalName.length>15||finalName.includes("/")||usedNames.has(finalName.toLowerCase())){const newName=await showRenameModal(entry.innerPath,tex.dataURL,suggested);if(!newName)continue;finalName=newName}tex.name=finalName;for(const orig of entry.originals){const pathMatch=orig.toLowerCase()===entry.innerPath.toLowerCase();if(pathMatch||entry.originals.length===1){bulkRT(orig,finalName)}}manualTextures[finalName.toLowerCase()]=tex;usedNames.add(finalName.toLowerCase())}catch(e){console.warn("Failed to import:",entry.file.name,e)}}}}dirty=true;updateSave();renderSidebar();renderResults();renderEditHistory();showToast("Folder import complete")};inp.click()}}

function initApp(){initPersistentWADs();
// Init recents panel state
try{recentsPanelOpen=localStorage.getItem("mapmig_recents_open")!=="0"}catch(e){recentsPanelOpen=!0}
const rp=document.getElementById("recentsPanel");const rb=document.getElementById("recentsToggleBtn");
if(recentsPanelOpen){rp.classList.add("open");rb.classList.add("active")}
if(window.MapMigBridge&&window.MapMigBridge.IS_TAURI){renderRecentsFromBridge()}else{renderRecents()}
// Set initial no-map sidebar state
document.getElementById("reloadBtn").style.display="none";
document.getElementById("resetBtn").textContent="";
//document.getElementById("overviewSection").style.display="none";
document.getElementById("wadsSection").style.display="none";
document.getElementById("saveBtn").style.display="none";
// Render initial tabbar with Settings only
document.querySelector('[id="fileName"]').setAttribute('hidden','');
const tabs=document.getElementById("tabList");tabs.innerHTML="";
const settingsTab={id:"settings",label:"Settings",icon:"\u2699"};
const b=document.createElement("button");b.className="tab-btn"+(activeTab==="settings"?" active":"");b.innerHTML='<span class="tab-icon">'+settingsTab.icon+"</span>"+settingsTab.label;
b.onclick=()=>{activeTab="settings";expandedItems=new Set;
document.getElementById("dropzone").style.display="none";
document.getElementById("main").classList.add("active");document.querySelector('[id="resetBtn"]').innerText="Load Map";
document.querySelector('[id="overviewSection"]').setAttribute('hidden','');
renderSidebar();renderResults()};tabs.appendChild(b);
if(window.MapMigBridge&&window.MapMigBridge.IS_TAURI){document.getElementById("fileInput").style.display="none";const selectBtn=document.querySelector(".btn-primary");if(selectBtn){selectBtn.onclick=async function(ev){ev.preventDefault();try{const path=await window.MapMigBridge.openFileDialog([{name:"MAP Files",extensions:["map"]}]);if(path)loadMap(path)}catch(err){showToast("Error: "+err)}}}}else{document.getElementById("fileInput").addEventListener("change",e=>{if(e.target.files.length)loadMap(e.target.files[0])})}document.getElementById("wadInput").addEventListener("change",async e=>{for(const f of e.target.files){try{const b=await f.arrayBuffer(),t=await parseWAD(b);Object.assign(wadTextures,t);if(!loadedWADNames.includes(f.name))loadedWADNames.push(f.name);wadBufferCache[f.name]=b;showToast("Loaded "+Object.keys(t).length+" textures from "+f.name)}catch(err){showToast("WAD error: "+err.message)}}renderSidebar();renderResults()});
// Drag-drop: Tauri v2 uses its own event system for file drops with full paths
if(window.MapMigBridge&&window.MapMigBridge.IS_TAURI){window.__TAURI_INTERNALS__.invoke("plugin:event|listen",{event:"tauri://drag-drop",target:{kind:"Any"},handler:window.__TAURI_INTERNALS__.transformCallback(function(ev){const payload=ev.payload||ev;const paths=payload.paths||[];console.log("[MapMig] Tauri drag-drop paths:",paths);for(const p of paths){const name=p.split(/[\\/]/).pop().toLowerCase();if(name.endsWith(".map")){loadMap(p)}else if(name.endsWith(".wad")){(async()=>{try{const buf=await window.MapMigBridge.readBinaryFile(p);const t=await parseWAD(buf);Object.assign(wadTextures,t);const nm=p.split(/[\\/]/).pop();if(!loadedWADNames.includes(nm))loadedWADNames.push(nm);wadBufferCache[nm]=buf;showToast("Loaded "+Object.keys(t).length+" textures from "+nm);renderSidebar();renderResults()}catch(err){showToast("WAD error: "+err)}})()}}})});
// Also handle dragover for visual feedback
document.body.addEventListener("dragover",e=>{e.preventDefault();e.stopPropagation()});document.body.addEventListener("drop",e=>{e.preventDefault();e.stopPropagation()})}else{
// Browser fallback: standard drag-drop with File objects
document.body.addEventListener("dragover",e=>{e.preventDefault();const d=document.getElementById("dropzone");if(d)d.classList.add("dragover")});document.body.addEventListener("dragleave",()=>{const d=document.getElementById("dropzone");if(d)d.classList.remove("dragover")});document.body.addEventListener("drop",e=>{e.preventDefault();const d=document.getElementById("dropzone");if(d)d.classList.remove("dragover");const fs=Array.from(e.dataTransfer.files),mf=fs.find(f=>f.name.endsWith(".map")),wfs=fs.filter(f=>f.name.endsWith(".wad"));if(mf)loadMap(mf);wfs.forEach(async f=>{try{const b=await f.arrayBuffer(),t=await parseWAD(b);Object.assign(wadTextures,t);if(!loadedWADNames.includes(f.name))loadedWADNames.push(f.name);wadBufferCache[f.name]=b;showToast("Loaded "+Object.keys(t).length+" textures from "+f.name);renderSidebar();renderResults()}catch(err){showToast("WAD error: "+err.message)}})})}
document.addEventListener("click",handleClick);document.addEventListener("change",handleChange);document.addEventListener("keydown",function(e){if((e.ctrlKey||e.metaKey)&&e.key==="z"&&!e.shiftKey){e.preventDefault();undoEdit()}else if((e.ctrlKey||e.metaKey)&&e.key==="z"&&e.shiftKey){e.preventDefault();redoEdit()}else if((e.ctrlKey||e.metaKey)&&e.key==="y"){e.preventDefault();redoEdit()}});
// Custom context menu
document.addEventListener("contextmenu",function(e){e.preventDefault();const old=document.getElementById("ctxMenu");if(old)old.remove();const menu=document.createElement("div");menu.id="ctxMenu";menu.className="ctx-menu";const sel=window.getSelection();const hasSel=sel&&sel.toString().length>0;const target=e.target;const isInput=target.tagName==="INPUT"||target.tagName==="TEXTAREA";const isImg=target.tagName==="IMG"&&!target.classList.contains("header-logo");const items=[];
items.push({label:"Cut",icon:"\u2702",action:async function(){if(isInput){const inp=target;const start=inp.selectionStart;const end=inp.selectionEnd;if(start!==end){const text=inp.value.substring(start,end);try{await navigator.clipboard.writeText(text)}catch(ex){}inp.value=inp.value.substring(0,start)+inp.value.substring(end);inp.selectionStart=inp.selectionEnd=start;inp.dispatchEvent(new Event("change",{bubbles:true}))}}},disabled:!isInput});
items.push({label:"Copy",icon:"\uD83D\uDCCB",action:async function(){if(isInput){const inp=target;const start=inp.selectionStart;const end=inp.selectionEnd;if(start!==end){try{await navigator.clipboard.writeText(inp.value.substring(start,end))}catch(ex){}}}else if(hasSel){try{await navigator.clipboard.writeText(sel.toString())}catch(ex){}}},disabled:!hasSel&&!isInput});
items.push({label:"Paste",icon:"\uD83D\uDCCB",action:async function(){if(isInput){try{const text=await navigator.clipboard.readText();const inp=target;const start=inp.selectionStart;const end=inp.selectionEnd;inp.value=inp.value.substring(0,start)+text+inp.value.substring(end);inp.selectionStart=inp.selectionEnd=start+text.length;inp.dispatchEvent(new Event("change",{bubbles:true}))}catch(ex){}}},disabled:!isInput});
items.push({label:"Select All",icon:"\u2610",action:function(){if(isInput){target.select()}else{const range=document.createRange();range.selectNodeContents(document.body);sel.removeAllRanges();sel.addRange(range)}},disabled:false});
if(isImg){items.push({sep:true});items.push({label:"Magnify Image",icon:"\uD83D\uDD0D",action:function(){const src=target.src;const natW=target.naturalWidth||target.width;const natH=target.naturalHeight||target.height;const dlg=document.createElement("div");dlg.id="magnifyDlg";dlg.style.cssText="position:fixed;inset:0;background:rgba(0,0,0,0.85);z-index:3000;display:flex;flex-direction:column;align-items:center;justify-content:center";let zoom=1;const maxZoom=8;const minZoom=0.25;const renderImg=function(){const img=dlg.querySelector("img");if(img){img.style.transform="scale("+zoom+")"}const lbl=dlg.querySelector(".zoom-label");if(lbl)lbl.textContent=Math.round(zoom*100)+"%"};dlg.innerHTML='<div style="margin-bottom:12px;display:flex;gap:12px;align-items:center"><button class="ctx-zoom-btn" data-zoom="out" style="background:#2a2a4a;border:1px solid #3a3a5a;color:#d0d0d0;padding:6px 14px;border-radius:4px;cursor:pointer;font-size:16px;font-family:Consolas,monospace">\u2212</button><span class="zoom-label" style="color:#aaa;font-size:13px;font-family:Consolas,monospace;min-width:50px;text-align:center">100%</span><button class="ctx-zoom-btn" data-zoom="in" style="background:#2a2a4a;border:1px solid #3a3a5a;color:#d0d0d0;padding:6px 14px;border-radius:4px;cursor:pointer;font-size:16px;font-family:Consolas,monospace">+</button><button class="ctx-zoom-btn" data-zoom="fit" style="background:#2a2a4a;border:1px solid #3a3a5a;color:#d0d0d0;padding:6px 12px;border-radius:4px;cursor:pointer;font-size:11px;font-family:Consolas,monospace">Fit</button><button class="ctx-zoom-btn" data-zoom="actual" style="background:#2a2a4a;border:1px solid #3a3a5a;color:#d0d0d0;padding:6px 12px;border-radius:4px;cursor:pointer;font-size:11px;font-family:Consolas,monospace">1:1</button><button class="ctx-zoom-btn" data-zoom="close" style="background:#d16969;border:none;color:#fff;padding:6px 12px;border-radius:4px;cursor:pointer;font-size:11px;font-family:Consolas,monospace">\u2715 Close</button></div><div style="overflow:auto;max-width:90vw;max-height:calc(90vh - 50px);display:flex;align-items:center;justify-content:center"><img src="'+src+'" style="image-rendering:pixelated;transform-origin:center;transition:transform 0.15s;border:1px solid #2a2a4a" width="'+natW+'" height="'+natH+'"></div><div style="margin-top:8px;color:#555;font-size:10px">'+natW+' \u00D7 '+natH+' px \u2014 Scroll to zoom</div>';document.body.appendChild(dlg);dlg.addEventListener("click",function(ev){const btn=ev.target.closest("[data-zoom]");if(btn){const z=btn.dataset.zoom;if(z==="in"){zoom=Math.min(maxZoom,zoom*1.5)}else if(z==="out"){zoom=Math.max(minZoom,zoom/1.5)}else if(z==="fit"){zoom=1}else if(z==="actual"){const vw=window.innerWidth*0.9;const vh=window.innerHeight*0.85;zoom=Math.min(vw/natW,vh/natH);zoom=1/zoom*zoom}else if(z==="close"){dlg.remove();return}renderImg()}else if(ev.target===dlg){dlg.remove()}});dlg.addEventListener("wheel",function(ev){ev.preventDefault();if(ev.deltaY<0){zoom=Math.min(maxZoom,zoom*1.2)}else{zoom=Math.max(minZoom,zoom/1.2)}renderImg()})},disabled:false})}
let h="";for(const item of items){if(item.sep){h+='<div class="ctx-menu-sep"></div>'}else{h+='<div class="ctx-menu-item'+(item.disabled?" disabled":"")+'" data-idx="'+items.indexOf(item)+'">'+item.icon+" "+item.label+"</div>"}}menu.innerHTML=h;menu.style.left=Math.min(e.clientX,window.innerWidth-170)+"px";menu.style.top=Math.min(e.clientY,window.innerHeight-200)+"px";document.body.appendChild(menu);menu.addEventListener("mousedown",function(ev){ev.preventDefault();ev.stopPropagation();const idx=ev.target.closest("[data-idx]");if(idx){const i=+idx.dataset.idx;menu.remove();if(isInput)target.focus();if(items[i]&&items[i].action){const result=items[i].action();if(result&&result.then)result.then(function(){}).catch(function(){})}return}menu.remove()});const dismiss=function(ev){if(!menu.contains(ev.target)){menu.remove();document.removeEventListener("mousedown",dismiss)}};setTimeout(function(){document.addEventListener("mousedown",dismiss)},0)});
window.addEventListener("beforeunload",e=>{if(dirty){e.preventDefault();e.returnValue=""}})}

function setWindowTitle(title){document.title=title;if(window.__TAURI_INTERNALS__){window.__TAURI_INTERNALS__.invoke("set_window_title",{title:title}).catch(()=>{})}}
function autoReplaceToolTextures(){const replacements={"tools/toolstrigger":"trigger","tools/toolsclip":"clip","tools/toolsskip":"skip"};let totalReplaced=0;for(const e of entities){for(const b of e.brushes){for(const f of b.faces){const lc=f.texture.toLowerCase();if(replacements[lc]){f.texture=replacements[lc];totalReplaced++}}}}if(totalReplaced>0){console.log("[MapMig] Auto-replaced "+totalReplaced+" tool texture"+(totalReplaced!==1?"s":""))}}
async function loadMap(f){document.querySelector('[id="fileName"]').removeAttribute('hidden','');document.querySelector('[id="overviewSection"]').removeAttribute('hidden','');console.log("[MapMig] loadMap called with:",typeof f==="string"?f:(f&&f.name?f.name:"unknown"),typeof f);if(window.MapMigBridge&&window.MapMigBridge.IS_TAURI&&typeof f==="string"){currentMapPath=f;console.log("[MapMig] Tauri path mode, reading:",f);mapFileName=await window.MapMigBridge.getFileName(f);const content=await window.MapMigBridge.readTextFile(f);parseMapFile(content);lastMapFile=f}else if(window.MapMigBridge&&window.MapMigBridge.IS_TAURI&&f&&f.path){currentMapPath=f.path;console.log("[MapMig] Tauri file.path mode, reading:",f.path);mapFileName=await window.MapMigBridge.getFileName(f.path);const content=await window.MapMigBridge.readTextFile(f.path);parseMapFile(content);lastMapFile=f.path}else{currentMapPath=null;lastMapFile=f;mapFileName=f.name;parseMapFile(await f.text())}autoReplaceToolTextures();console.log("[MapMig] Loaded OK, currentMapPath:",currentMapPath,"mapFileName:",mapFileName);setWindowTitle(mapFileName+" - MapMig");editHistory=[{type:"file_opened"}];historyPos=0;dirty=!1;expandedItems=new Set;checkedEntities=new Set;editAllGroups=new Set;activeTab="entities";tabScrollPositions={};addRecent(mapFileName,currentMapPath);renderApp()}
async function reloadMap(){if(!lastMapFile&&!currentMapPath)return;const doReload=async()=>{if(window.MapMigBridge&&window.MapMigBridge.IS_TAURI&&currentMapPath){const content=await window.MapMigBridge.readTextFile(currentMapPath);parseMapFile(content)}else if(lastMapFile&&lastMapFile.text){parseMapFile(await lastMapFile.text())}autoReplaceToolTextures();editHistory=[{type:"file_opened"}];historyPos=0;dirty=!1;expandedItems=new Set;checkedEntities=new Set;editAllGroups=new Set;setWindowTitle(mapFileName+" - MapMig");renderApp();showToast("Reloaded "+mapFileName)};if(dirty){mmConfirm("You have unsaved changes. Reload anyway?",doReload)}else{await doReload()}}

window.saveMap=saveMap;window.saveMapAs=saveMapAs;window.showToast=showToast;window.toggle=toggle;window.renderResults=renderResults;window.renderSidebar=renderSidebar;window.getEntityGroups=getEntityGroups;window.getAllTextures=getAllTextures;window.reloadMap=reloadMap;window.toggleRecentsPanel=toggleRecentsPanel;window.clearRecents=clearRecents;window.refreshWADs=refreshWADs;window.showAboutModal=showAboutModal;window.importImageFile=importImageFile;window.importImagesFolder=importImagesFolder;
document.addEventListener("DOMContentLoaded",initApp);
